#!/usr/bin/env node
/**
 * Create Gmail drafts from nightly pipeline email JSON files.
 * ──────────────────────────────────────────────────────────
 * This script reads the email JSON files generated by nightly-pipeline.mjs
 * and creates drafts in Ferdie's Gmail (ferdie@norbotsystems.com).
 *
 * Two modes:
 *   1. Cowork MCP mode (default): Uses the Gmail MCP connector available in Cowork
 *   2. Claude CLI mode: Generates a prompt for Claude CLI to create drafts
 *
 * Usage:
 *   node scripts/create-gmail-drafts.mjs --run-dir /tmp/nightly-pipeline/nightly-2026-02-27-xxx
 *   node scripts/create-gmail-drafts.mjs --run-dir /tmp/nightly-pipeline/nightly-2026-02-27-xxx --mode cli
 *
 * In Cowork mode, this script outputs structured instructions that the Cowork
 * session uses to call gmail_create_draft via MCP.
 */

import { parseArgs } from 'node:util';
import { readFileSync, readdirSync, existsSync, writeFileSync } from 'node:fs';
import { resolve, join } from 'node:path';

const { values: args } = parseArgs({
  options: {
    'run-dir': { type: 'string' },
    mode: { type: 'string', default: 'cowork' },
    help: { type: 'boolean' },
  },
});

if (args.help || !args['run-dir']) {
  console.log('Usage: node scripts/create-gmail-drafts.mjs --run-dir /tmp/nightly-pipeline/nightly-xxx');
  console.log('Modes: cowork (default), cli');
  process.exit(args.help ? 0 : 1);
}

const runDir = args['run-dir'];
if (!existsSync(runDir)) {
  console.error(`Run directory not found: ${runDir}`);
  process.exit(1);
}

// Find all email JSON files
const emailFiles = readdirSync(runDir).filter(f => f.endsWith('-email.json'));

if (emailFiles.length === 0) {
  console.log('No email files found in run directory.');
  process.exit(0);
}

console.log(`\nFound ${emailFiles.length} email drafts to create\n`);

const drafts = [];
const warnings = [];

for (const file of emailFiles) {
  const email = JSON.parse(readFileSync(join(runDir, file), 'utf-8'));

  // Run quality checks
  const checks = email.qualityChecks || {};
  const failedChecks = Object.entries(checks).filter(([, v]) => v === 'FAIL');

  if (failedChecks.length > 0) {
    warnings.push({
      file,
      business: email.metadata?.siteId,
      failures: failedChecks.map(([k, v]) => `${k}: ${v}`),
    });
    console.log(`  ⚠ SKIPPED ${file}: quality check failed — ${failedChecks.map(([k]) => k).join(', ')}`);
    continue;
  }

  if (!email.to) {
    console.log(`  ⚠ SKIPPED ${file}: no email address`);
    continue;
  }

  drafts.push({
    to: email.to,
    subject: email.subject,
    body: email.body,
    siteId: email.metadata?.siteId,
    demoUrl: email.metadata?.demoUrl,
  });

  console.log(`  ✓ ${email.to} — "${email.subject}"`);
}

console.log(`\n${drafts.length} drafts ready, ${warnings.length} skipped\n`);

if (drafts.length === 0) {
  console.log('No drafts to create.');
  process.exit(0);
}

// ─── Output based on mode ───────────────────────────────────────────────────

if (args.mode === 'cli') {
  // Generate a prompt for Claude CLI to create Gmail drafts
  const prompt = buildClaudePrompt(drafts);
  const promptPath = join(runDir, 'gmail-draft-prompt.txt');
  writeFileSync(promptPath, prompt);
  console.log(`Claude CLI prompt written to: ${promptPath}`);
  console.log(`\nRun:\n  claude -p "$(cat ${promptPath})"\n`);
} else {
  // Output structured JSON for Cowork MCP consumption
  const outputPath = join(runDir, 'gmail-drafts-to-create.json');
  writeFileSync(outputPath, JSON.stringify(drafts, null, 2));
  console.log(`Draft instructions written to: ${outputPath}`);
  console.log(`\nIn a Cowork session, these will be created via gmail_create_draft MCP tool.`);
}

if (warnings.length > 0) {
  console.log('\n⚠ Quality Warnings:');
  for (const w of warnings) {
    console.log(`  ${w.business}: ${w.failures.join(', ')}`);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// HELPER
// ═══════════════════════════════════════════════════════════════════════════

function buildClaudePrompt(drafts) {
  let prompt = `Create ${drafts.length} Gmail drafts in ferdie@norbotsystems.com. `;
  prompt += `Use the gmail_create_draft tool for each. Do NOT send them — drafts only.\n\n`;

  for (let i = 0; i < drafts.length; i++) {
    const d = drafts[i];
    prompt += `Draft ${i + 1}:\n`;
    prompt += `To: ${d.to}\n`;
    prompt += `Subject: ${d.subject}\n`;
    prompt += `Body:\n${d.body}\n\n`;
  }

  prompt += `After creating all drafts, confirm the count and list the subjects.\n`;
  return prompt;
}
